import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
  } catch (e) {}
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

/**
 * Strips markdown code blocks and other non-JSON debris from Gemini responses.
 */
function cleanJsonResponse(text: string): string {
  if (!text) return "{}";
  // Remove markdown code block markers
  let cleaned = text.trim();
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/, "").replace(/\n?```$/, "");
  }
  return cleaned.trim();
}

function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], i];
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

/**
 * PHASE 1: Fast Core Translation
 */
export async function translateWordCore(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  // Use API key directly as per strict instructions
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `System: Philological Lexicon. 
Task: Analyze and translate "${query}" from ${sourceLanguage} to ${targetLanguage}.

STRICT LANGUAGE CONSTRAINTS:
- Primary translation MUST be in ${targetLanguage}.
- Synonyms MUST be in ${sourceLanguage}.
- Semantic variations MUST be in ${targetLanguage}.
- DO NOT use German results if neither language is German.
- If ${sourceLanguage} is Arabic, synonyms MUST be in Arabic script.
- If ${sourceLanguage} is German, include gender and plural forms.

Precision Requirements:
1. Provide the primary translation in ${targetLanguage}.
2. Provide synonyms of "${query}" in ${sourceLanguage}.
3. Provide semantic variations in ${targetLanguage}.
4. Provide the CEFR level (A1-C2) if applicable.

Output: JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          cefrLevel: { type: Type.STRING, description: "CEFR Level (e.g., A1, B2)" },
          synonyms: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }
          },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "partOfSpeech"]
      }
    }
  });

  const rawData = JSON.parse(cleanJsonResponse(response.text || '{}'));

  return {
    id: generateId(),
    term: rawData.term || query,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    cefrLevel: sourceLanguage !== 'Uzbek' ? rawData.cefrLevel : undefined,
    philology: {
      etymology: "", 
      partOfSpeech: rawData.partOfSpeech,
      gender: rawData.gender,
      plural: rawData.plural
    },
    culture: { usage: "", register: 'neutral', notes: "" },
    synonyms: rawData.synonyms || [],
    variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
    literature: [],
    realLifeSentences: [],
    idioms: [],
    timestamp: Date.now()
  };
}

/**
 * PHASE 2: Archival Enrichment
 */
export async function enrichLexicalEntry(entry: LexicalEntry): Promise<Partial<LexicalEntry>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Senior Philologist Mode: Provide scholarly enrichment for the term "${entry.term}".
  Source Language: ${entry.sourceLang}
  Target Language: ${entry.targetLang}

  STRICT LINGUISTIC ISOLATION:
  - All 'literature' text MUST be in ${entry.sourceLang}.
  - All 'idioms' source text (the 'text' field) MUST be in ${entry.sourceLang}.
  - Translations MUST be in ${entry.targetLang}.
  - DO NOT provide German quotes or sentences unless ${entry.sourceLang} is German.
  - If the source is Arabic, all source text MUST be in Arabic script.

  Requirements:
  1. Detailed Etymology: History of "${entry.term}".
  2. Literature: TWO quotes using "${entry.term}". Quote 1 should be simple.
  3. Natural Usage & Idioms: TWO high-quality sentences in ${entry.sourceLang} featuring "${entry.term}".
     - Sentence 1: Natural/Common usage.
     - Sentence 2: Idiomatic/Metaphorical.

  CRITICAL: Both examples in the 'idioms' JSON field MUST contain the search term "${entry.term}" in the source text and MUST be written in ${entry.sourceLang}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            usage: { type: Type.STRING },
            register: { type: Type.STRING },
            notes: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              },
              minItems: 2
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING, description: `Sentence in ${entry.sourceLang} containing the term` },
                  translation: { type: Type.STRING, description: `Translation in ${entry.targetLang}` },
                  context: { type: Type.STRING, description: "Label as 'Natural Usage' or 'Idiomatic Expression'" }
                }
              },
              minItems: 2,
              maxItems: 2
            }
          }
        }
      }
    });

    const raw = JSON.parse(cleanJsonResponse(response.text || '{}'));
    return {
      philology: { ...entry.philology, etymology: raw.etymology || "Archival retrieval synchronized." },
      culture: {
        usage: raw.usage || "Standard scholarly use",
        register: raw.register || 'neutral',
        notes: raw.notes || ""
      },
      literature: raw.literature || [],
      realLifeSentences: raw.idioms || [], 
      idioms: raw.idioms || []
    };
  } catch (err) {
    return {
      philology: { ...entry.philology, etymology: "Archival record retrieved." }
    };
  }
}

/**
 * Scholarly Daily Insight
 */
export async function getDailyInsight() {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = "Generate a sophisticated 'Linguistic Fact of the Day' relating to the intersection of German, Uzbek, Arabic, or Russian. Focus on etymology or cognates. Output as JSON.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            fact: { type: Type.STRING },
            source: { type: Type.STRING }
          },
          required: ["title", "fact"]
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (err) {
    return { 
      title: "Lexical Continuity", 
