/**
 * Arena Quiz Generation
 */
export async function generateQuiz(entries: LexicalEntry[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const context = entries.map(e => `${e.term} (${e.sourceLang}) <-> ${e.mainTranslation} (${e.targetLang})`).join(", ");

  const prompt = `Task: Create a simple multiple-choice vocabulary quiz based on these translations: ${context}.
Rules:
1. Max 2 simple questions per word.
2. Question style: Use ONLY the word itself as the question (e.g. "Tisch").
3. Directionality:
   - Type A: Question is Source Term -> Options are Target Translations.
   - Type B: Question is Target Translation -> Options are Source Terms.
4. Options style: Provide exactly 3 options. Options must be simple single words.
5. Distractors: Must be words of the same language as the correct answer, ideally unrelated or commonly confused.
6. Example: 
   Question: "Tisch"
   Options: ["ruchka", "stol", "chiroq"]
   CorrectAnswer: "stol"
7. Output format: JSON Array of objects.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            },
            required: ["question", "correctAnswer", "options", "explanation"]
          }
        }
      }
    });

    const questions = JSON.parse(cleanJsonResponse(response.text || '[]'));
    return questions.map((q: any) => ({
      ...q,
      options: shuffleArray(q.options)
    }));
  } catch (err) {
    console.error("Quiz gen error:", err);
    return [];
  }
}

import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;
let isResuming = false;

/**
 * Standardizes the AudioContext retrieval.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
    if (AudioContextClass) {
      sharedAudioCtx = new AudioContextClass({ sampleRate: 24000 });
    }
  }
  return sharedAudioCtx;
}

/**
 * Robustly resumes the AudioContext within a user gesture.
 */
export async function resumeAudioContext(): Promise<void> {
  const ctx = getAudioContext();
  if (!ctx || isResuming) return;

  if (ctx.state === 'running') return;

  isResuming = true;
  try {
    await ctx.resume();

    // Critical iOS/macOS Fix: Inject a tiny silent buffer to "warm" the audio hardware.
    const buffer = ctx.createBuffer(1, 1, 24000);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  } catch (e) {
    // Silent catch for environment restrictions
  } finally {
    isResuming = false;
  }
}

/**
 * Custom base64 decoder with padding handling.
 */
function decode(base64: string): Uint8Array {
  // Normalize base64 for iOS if needed (ensure padding)
  const normalized = base64.replace(/\s/g, '');
  const binaryString = atob(normalized);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Decodes raw PCM 16-bit audio bytes into an AudioBuffer.
 */
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const arrayBuffer = data.buffer.slice(data.byteOffset, data.byteOffset + data.byteLength);
  const dataInt16 = new Int16Array(arrayBuffer);

  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Synthesizes and plays text via Gemini TTS.
 */
export async function speak(text: string, lang: Language): Promise<void> {
  if (!text || !text.trim()) return;

  const ctx = getAudioContext();
  if (!ctx) return;

  const cacheKey = `${text.trim()}:${lang}`;

  const playBuffer = (buffer: AudioBuffer) => {
    if (ctx.state !== 'running') {
      ctx.resume().catch(() => {});
    }
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start(0);
  };

  if (audioBufferCache.has(cacheKey)) {
    playBuffer(audioBufferCache.get(cacheKey)!);
    return;
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const voiceName = VOICE_MAPPING[lang] || 'Puck';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
    audioBufferCache.set(cacheKey, audioBuffer);
    playBuffer(audioBuffer);
  } catch (error) {
    console.error("Philologist Voice Engine Failure:", error);
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

/**
 * Robustly sanitizes text, handling iOS smart punctuation and common Turkic/German characters.
 */
const normalizeQuery = (text: string, lang: Language): string => {
  if (!text) return "";
  let res = text.trim().toLowerCase();

  // Sanitize Smart Punctuation (iOS common issue)
  res = res
    .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'") // Smart Single Quotes
    .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"') // Smart Double Quotes
    .replace(/\u2013/g, "-") // En-dash
    .replace(/\u2014/g, "--"); // Em-dash

  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');

  const [sourceLang, setSourceLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexSourceLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'German');
  });

  const [targetLang, setTargetLang] = useState<Language>(() => {
    const saved = localStorage.getItem('lexTargetLang');
    return (LANGUAGES_LIST.includes(saved as Language) ? (saved as Language) : 'Uzbek');
  });

  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setVoiceSupported(false);
    }
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      localStorage.setItem('lexSourceLang', selectedEntry.sourceLang);
      localStorage.setItem('lexTargetLang', selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading) {
      setShowSuggestions(false);
      setSuggestions([]);
      return;
    }

    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().startsWith(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        if (!loading && !(result && result.term.toLowerCase() === query.trim().toLowerCase())) {
          setSuggestions(unique);
          setShowSuggestions(unique.length > 0);
          setSelectedIndex(-1);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 150);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading, result]);

  const startVoiceSearch = async () => {
    await resumeAudioContext().catch(() => {});
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
      setVoiceStatusMsg("Voice access restricted");
      triggerHaptic('error');
      setTimeout(() => setVoiceStatusMsg(null), 3000);
      return;
    }

    const recognition = new SpeechRecognition();
    const langCodes: Record<Language, string> = {
      German: 'de-DE', Uzbek: 'uz-UZ', English: 'en-US', Russian: 'ru-RU', Arabic: 'ar-SA'
    };

    recognition.lang = langCodes[sourceLang];
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => { setIsListening(true); triggerHaptic('light'); };
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setQuery(transcript);
      handleSearch(transcript);
    };
    recognition.onerror = () => { setIsListening(false); triggerHaptic('error'); };
    recognition.onend = () => setIsListening(false);

    try { recognition.start(); } catch (e) { setIsListening(false); }
  };

  const handleSearch = async (overrideQuery?: string) => {
    await resumeAudioContext().catch(() => {});
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    setSearchError(null);
    if (inputRef.current) inputRef.current.blur();
    setQuery(cleanQuery);

    const normQuery = normalizeQuery(cleanQuery, sourceLang);
    const localHit = history.find(e => normalizeQuery(e.term, e.sourceLang) === normQuery && e.sourceLang === sourceLang && e.targetLang === targetLang);

    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        speak(cleanQuery, sourceLang).then(() => speak(localHit.mainTranslation, targetLang)).catch(() => {});
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          speak(cleanQuery, sourceLang).then(() => speak(globalHit.mainTranslation, targetLang)).catch(() => {});
        }
        return;
      }

      const coreEntry = await translateWordCore(cleanQuery, sourceLang, targetLang);
      coreEntry.normalizedTerm = normQuery;

      setResult(coreEntry);
      setLoading(false);

      if (autoAudio) {
        speak(cleanQuery, sourceLang).then(() => speak(coreEntry.mainTranslation, targetLang)).catch(() => {});
      }

      const enrichment = await enrichLexicalEntry(coreEntry);
      const fullEntry = { ...coreEntry, ...enrichment };

      setResult(fullEntry);
      onEntrySaved(fullEntry);
      saveGlobalEntry(fullEntry);
    } catch (err: any) {
      console.error("Philological search failed:", err);
      setSearchError("The archive is silent. Network or API error occurred.");
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      setShowSuggestions(false);
      if (showSuggestions && selectedIndex >= 0) {
        const selectedTerm = suggestions[selectedIndex].term;
        setQuery(selectedTerm);
        handleSearch(selectedTerm);
      } else {
        handleSearch();
      }
      return;
    }

    if (!showSuggestions) return;
    if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(prev => (prev + 1) % suggestions.length); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length); }
    else if (e.key === 'Escape') { setShowSuggestions(false); }
  };

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      {/* Search Header Controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[3px] border-[#7c1a1a] pl-4">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-500 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-[0.2em] text-stone-400 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-100/50 p-2 rounded-sm w-full sm:w-auto border border-stone-200">
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => { setSourceLang(full); localStorage.setItem('lexSourceLang', full); }} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>
